#!/usr/bin/env bash
# scripts/check-structure.sh

ROOT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/../src" && pwd)"
OUTPUT_FILE="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)/STRUCTURE.md"

indent() {
  local level=$1
  for ((i = 0; i < level; i++)); do
    printf "  "
  done
}

# เก็บไฟล์ .ts, .tsx ทั้งหมดแบบ relative path
mapfile -t entries < <(find "$ROOT_DIR" -type f \( -name "*.ts" -o -name "*.tsx" \) | sed "s|^$ROOT_DIR/||" | sort)

declare -A seen
output=""

for entry in "${entries[@]}"; do
  IFS='/' read -ra parts <<< "$entry"
  current=""
  for i in "${!parts[@]}"; do
    current+="${parts[i]}"
    key="${i}-${current}"

    if [[ -z "${seen[$key]}" ]]; then
      seen["$key"]=1

      # เช็คว่าชิ้นนี้คือไฟล์หรือโฟลเดอร์ (ไฟล์จะอยู่ตำแหน่งสุดท้าย และมี dot)
      if [[ $i -eq $((${#parts[@]} - 1)) && "${parts[i]}" == *.* ]]; then
        # ไฟล์ ไม่ต้องขึ้นบรรทัด / ต่อ
        output+=$(indent "$i")"- ${parts[i]}"$'\n'
      else
        # โฟลเดอร์ ใส่ / ต่อท้าย
        output+=$(indent "$i")"- ${parts[i]}/"$'\n'
      fi
    fi
    current+="/"
  done
done

{
  echo "# 📁 Project Source Structure (\`src/\`)"
  echo
  echo '```text'
  echo "$output"
  echo '```'
  echo
  echo '> ✅ Generated by `scripts/check-structure.sh`'
  echo '> ℹ️ NOTE: โค้ดทั้งหมดทำงานภายใต้แนวทาง Dev to Dev แบบเข้มงวด ตรวจสอบโครงสร้างโปรเจกต์ให้เป็นระบบ หลีกเลี่ยงการแตกไฟล์นอกคำสั่งหรือ generate ที่ไม่คำสั่ง    นี่คือรายละเอียดเว็บไซต์ของเรา  กำหนดให้ AI CHAT GPT เป็นนักออกแบบเว็บไซต์ และเขียน Code ระดับ Professional ตอบสนองดีทั้งบนมือถือและเดสทอปรายละเอียดเนื้อหาdependencies:                                         @faker-js/faker 9.9.0                                 @headlessui/react 2.2.7                               @heroicons/react 2.2.0                                @radix-ui/react-slot 1.2.3                            axios 1.11.0                                          bcryptjs 3.0.2                                        clsx 2.1.1                                            crypto-browserify 3.12.1                              framer-motion 12.23.12                                html2canvas 1.4.1                                     install 0.13.0                                        jspdf 3.0.1                                           lucide-react 0.537.0                                  react 19.1.1                                          react-dom 19.1.1                                      react-hook-form 7.62.0                                react-icons 5.5.0                                     react-qr-code 2.0.18                                  react-router-dom 7.8.0                                tailwind-merge 3.3.1                                  zod 4.0.17                                                                                                  devDependencies:                                      @eslint/js 9.33.0                                     @tailwindcss/aspect-ratio 0.4.2                       @tailwindcss/forms 0.5.10                             @tailwindcss/line-clamp 0.4.4                         @tailwindcss/postcss 4.1.11                           @tailwindcss/typography 0.5.16                        @types/node 24.2.1                                    @types/react 19.1.10                                  @types/react-dom 19.1.7                               @typescript-eslint/eslint-plugin 8.39.1               @typescript-eslint/parser 8.39.1                      @vitejs/plugin-react 5.0.0                            autoprefixer 10.4.21                                  daisyui 5.0.50                                        esbuild 0.25.8                                        eslint 9.33.0                                         eslint-config-prettier 10.1.8                         eslint-plugin-prettier 5.5.4                          eslint-plugin-react 7.37.5                            eslint-plugin-react-hooks 5.2.0                       eslint-plugin-react-refresh 0.4.20                    globals 16.3.0                                        husky 8.0.3                                           lint-staged 16.1.5                                    postcss 8.5.6                                         prettier 3.6.2                                        tailwindcss 3.3.2                                     ts-node 10.9.2                                        tsconfig-paths 4.2.0                                  typescript 5.9.2
typescript-eslint 8.39.0
vite 7.1.2
vite-tsconfig-paths 5.1.4
zip-a-folder 3.1.9
🛠️ Dev@JP ~/projectjp
'
} > "$OUTPUT_FILE"

echo "✅ STRUCTURE.md generated at: $OUTPUT_FILE"